import sys

def solve():
    N, S, R = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))

    def is_calm(block):
        return sum(block) <= S and max(block) - min(block) <= R

    count = 0
    for i in range(N):
        for j in range(i + 1, N + 1):
            block = A[i:j]
            if is_calm(block):
                count += 1
    print(count)

if __name__ == "__main__":
    solve()
